import{P as o}from"./chunks/PublicUtilityPanel.QYoIU9MT.js";import{o as s,c as e,ag as i,E as r}from"./chunks/framework.DmPmGTlv.js";import"./chunks/theme.BsBmJ8k5.js";const u=JSON.parse('{"title":"Acesso","description":"","frontmatter":{},"headers":[],"relativePath":"acesso.md","filePath":"pt/acesso.md","lastUpdated":1777060498000}'),c={name:"acesso.md"},m=Object.assign(c,{setup(t){return(l,a)=>(s(),e("div",null,[a[0]||(a[0]=i('<h1 id="acesso" tabindex="-1">Acesso <a class="header-anchor" href="#acesso" aria-label="Permalink to &quot;Acesso&quot;">​</a></h1><blockquote><p>O acesso à cannabis medicinal no Brasil passa por critérios clínicos, documentais, sanitários e, em alguns casos, associativos. Esta página organiza o caminho sem prometer resultado individual.</p></blockquote><h2 id="rotas-principais-de-acesso" tabindex="-1">Rotas principais de acesso <a class="header-anchor" href="#rotas-principais-de-acesso" aria-label="Permalink to &quot;Rotas principais de acesso&quot;">​</a></h2><div class="docs-grid docs-grid-3"><article class="surface-card"><p class="docs-kicker">Rota 1</p><h3>Farmácia ou drogaria</h3><p> Quando houver produto regularizado dentro do marco da Anvisa, o acesso pode ocorrer pela rede autorizada, sempre conforme prescrição, controle sanitário e regras aplicáveis ao produto. </p></article><article class="surface-card"><p class="docs-kicker">Rota 2</p><h3>Importação excepcional</h3><p> A Anvisa mantém rota específica para pessoa física importar produto derivado de cannabis para uso próprio, com cadastro, análise e documentação. </p></article><article class="surface-card"><p class="docs-kicker">Rota 3</p><h3>Associação de pacientes</h3><p> A ABPCM organiza acolhimento, triagem documental, orientação e fluxos próprios de associação, seguindo regras públicas, políticas do site e exigências aplicáveis ao caso concreto. </p></article></div><h2 id="passo-a-passo-pratico" tabindex="-1">Passo a passo prático <a class="header-anchor" href="#passo-a-passo-pratico" aria-label="Permalink to &quot;Passo a passo prático&quot;">​</a></h2><div class="surface-card"><ol class="stack-list"><li><strong>Consulta e prescrição:</strong> o primeiro passo continua sendo a avaliação clínica com profissional habilitado. </li><li><strong>Definição da rota:</strong> com a prescrição em mãos, defina se o caso seguirá por farmácia, importação excepcional ou associação. </li><li><strong>Organização documental:</strong> separe documentos pessoais, comprovante de endereço, receita, laudo e anexos necessários. </li><li><strong>Validação operacional:</strong> confirme exigências atuais no site oficial da ABPCM e nas páginas oficiais da Anvisa antes de pagar, importar, associar-se ou agendar qualquer etapa. </li></ol></div><h2 id="checklist-documental-do-associado" tabindex="-1">Checklist documental do associado <a class="header-anchor" href="#checklist-documental-do-associado" aria-label="Permalink to &quot;Checklist documental do associado&quot;">​</a></h2><div class="docs-grid docs-grid-2"><article class="surface-card"><p class="docs-kicker">Documentos básicos</p><ul class="stack-list"><li>Documento oficial com foto.</li><li>Comprovante de endereço.</li><li>Receita válida.</li><li>Laudo ou relatório com CID-10, quando aplicável.</li><li>Documentos complementares exigidos pela rota escolhida.</li></ul></article><article class="surface-card"><p class="docs-kicker">Observação importante</p><p> A página pública de associação da ABPCM informa requisitos e documentação, mas a lista pode evoluir. Antes de concluir o processo, confirme sempre a versão mais atual no formulário oficial. </p><p><a href="https://www.abpcm.org.br/associe-se" target="_blank" rel="noreferrer"> Conferir requisitos atuais </a></p></article></div><h2 id="fontes-oficiais-para-o-paciente" tabindex="-1">Fontes oficiais para o paciente <a class="header-anchor" href="#fontes-oficiais-para-o-paciente" aria-label="Permalink to &quot;Fontes oficiais para o paciente&quot;">​</a></h2><div class="docs-grid docs-grid-2"><article class="surface-card"><p class="docs-kicker">Anvisa</p><h3>Importação e informações regulatórias</h3><div class="link-cluster"><a href="https://www.gov.br/anvisa/pt-br/assuntos/medicamentos/controlados/cannabis" class="link-pill" target="_blank" rel="noreferrer"> Página da Anvisa </a></div></article><article class="surface-card"><p class="docs-kicker">ABPCM</p><h3>Entrada pela associação</h3><div class="link-cluster"><a href="https://www.abpcm.org.br/associe-se" class="link-pill" target="_blank" rel="noreferrer"> Associe-se </a><a href="https://www.abpcm.org.br/general-5" class="link-pill" target="_blank" rel="noreferrer"> Políticas do site </a></div></article></div><h2 id="o-que-nao-pular" tabindex="-1">O que não pular <a class="header-anchor" href="#o-que-nao-pular" aria-label="Permalink to &quot;O que não pular&quot;">​</a></h2><div class="surface-card"><ul class="stack-list"><li>Não compre, importe ou utilize produto sem prescrição e sem checagem da rota aplicável.</li><li>Não confunda informação pública com autorização automática.</li><li>Não trate documentos clínicos, associativos e sanitários como mera formalidade.</li><li>Use a página [Guia do paciente](/guia-do-paciente) para preparar consulta, adesão e acompanhamento.</li></ul></div><h2 id="utilidades-publicas" tabindex="-1">Utilidades públicas <a class="header-anchor" href="#utilidades-publicas" aria-label="Permalink to &quot;Utilidades públicas&quot;">​</a></h2>',13)),r(o)]))}});export{u as __pageData,m as default};
